package ru.memearena.media.infrastructure;
import io.minio.*; import io.minio.errors.*; import jakarta.annotation.PostConstruct; import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty; import org.springframework.beans.factory.annotation.Value; import org.springframework.http.HttpStatus; import org.springframework.stereotype.Component; import ru.memearena.error.*; import ru.memearena.media.application.MediaStorage; import java.io.InputStream;
@org.springframework.context.annotation.Profile("!test") @Component @ConditionalOnProperty(name="media.storage.type",havingValue="minio",matchIfMissing=true) public class MinioMediaStorage implements MediaStorage { private final MinioClient client; private final String bucket; public MinioMediaStorage(@Value("${media.storage.minio.endpoint:${MINIO_ENDPOINT:http://localhost:9000}}") String endpoint,@Value("${media.storage.minio.access-key:${MINIO_ACCESS_KEY:minio}}") String accessKey,@Value("${media.storage.minio.secret-key:${MINIO_SECRET_KEY:minio_password}}") String secretKey,@Value("${media.storage.minio.bucket:${MINIO_BUCKET:meme-images}}") String bucket){this.client=MinioClient.builder().endpoint(endpoint).credentials(accessKey,secretKey).build();this.bucket=bucket;} @PostConstruct void init(){try{if(!client.bucketExists(BucketExistsArgs.builder().bucket(bucket).build())) client.makeBucket(MakeBucketArgs.builder().bucket(bucket).build());}catch(Exception e){throw new ApiException(HttpStatus.SERVICE_UNAVAILABLE,ErrorCode.MEDIA_STORAGE_UNAVAILABLE,"Media storage unavailable");}} public void put(String key,InputStream data,long size,String type){try{client.putObject(PutObjectArgs.builder().bucket(bucket).object(key).stream(data,size,-1).contentType(type).build());}catch(Exception e){throw new ApiException(HttpStatus.SERVICE_UNAVAILABLE,ErrorCode.MEDIA_STORAGE_UNAVAILABLE,"Media storage unavailable");}} public InputStream get(String key){try{return client.getObject(GetObjectArgs.builder().bucket(bucket).object(key).build());}catch(Exception e){throw new ApiException(HttpStatus.SERVICE_UNAVAILABLE,ErrorCode.MEDIA_STORAGE_UNAVAILABLE,"Media storage unavailable");}} public void delete(String key){try{client.removeObject(RemoveObjectArgs.builder().bucket(bucket).object(key).build());}catch(Exception e){throw new ApiException(HttpStatus.SERVICE_UNAVAILABLE,ErrorCode.MEDIA_STORAGE_UNAVAILABLE,"Media storage unavailable");}} }
